// ImportState accepts the Application ARN as the import ID. The ARN is used
// directly for GetApplication; the ID is parsed from the read response.
//
// Import command:
//
//	terraform import awsext_appintegrations_application.example arn:aws:app-integrations:us-east-1:123456789012:application/<id>
func (r *AppIntegrationsApplicationResource) ImportState(ctx context.Context, req resource.ImportStateRequest, resp *resource.ImportStateResponse) {
	if req.ID == "" {
		resp.Diagnostics.AddError(
			"Invalid import ID",
			"Import ID must be the Application ARN (arn:aws:app-integrations:...:application/<id>).",
		)
		return
	}
	// Store the ARN in application_arn; Read will populate all other fields including application_id.
	resp.Diagnostics.Append(resp.State.SetAttribute(ctx, path.Root("application_arn"), req.ID)...)
}

