func readAppIntegrationsTags(ctx context.Context, conn *appintegrations.Client, arn string) (types.Map, error) {
	out, err := conn.ListTagsForResource(ctx, &appintegrations.ListTagsForResourceInput{
		ResourceArn: aws.String(arn),
	})
	if err != nil {
		return types.MapNull(types.StringType), err
	}
	result, diags := types.MapValueFrom(ctx, types.StringType, out.Tags)
	if diags.HasError() {
		return types.MapNull(types.StringType), fmt.Errorf("error converting appintegrations tags to map")
	}
	return result, nil
}

func updateAppIntegrationsTags(ctx context.Context, conn *appintegrations.Client, arn string, oldTags, newTags types.Map) error {
	var oldTagMap, newTagMap map[string]string

	if !oldTags.IsNull() && !oldTags.IsUnknown() {
		oldTags.ElementsAs(ctx, &oldTagMap, false)
	}
	if !newTags.IsNull() && !newTags.IsUnknown() {
		newTags.ElementsAs(ctx, &newTagMap, false)
	}

	var keysToDelete []string
	for k := range oldTagMap {
		if _, exists := newTagMap[k]; !exists {
			keysToDelete = append(keysToDelete, k)
		}
	}

	if len(keysToDelete) > 0 {
		if _, err := conn.UntagResource(ctx, &appintegrations.UntagResourceInput{
			ResourceArn: aws.String(arn),
			TagKeys:     keysToDelete,
		}); err != nil {
			return err
		}
	}

	if len(newTagMap) > 0 {
		if _, err := conn.TagResource(ctx, &appintegrations.TagResourceInput{
			ResourceArn: aws.String(arn),
			Tags:        newTagMap,
		}); err != nil {
			return err
		}
	}

	return nil
}

func appIntegrationsTagsFromMap(ctx context.Context, tags types.Map) (map[string]string, error) {
	if tags.IsNull() || tags.IsUnknown() {
		return nil, nil
	}
	var tagMap map[string]string
	if diags := tags.ElementsAs(ctx, &tagMap, false); diags.HasError() {
		return nil, fmt.Errorf("error reading appintegrations tags")
	}
	return tagMap, nil
}
